code = """import json
import re

# Load all data
reviews_file = locals()['var_functions.query_db:14']
business_file = locals()['var_functions.query_db:34']

with open(reviews_file, 'r') as f:
    reviews_data = json.load(f)

with open(business_file, 'r') as f:
    business_data = json.load(f)

print(f'Loaded {len(reviews_data)} reviews and {len(business_data)} businesses')

# Create business lookup table: business_id -> description
business_lookup = {}
for business in business_data:
    business_id = business.get('business_id')
    if business_id:
        num_id = business_id.replace('businessid_', '')
        description = business.get('description', '')
        business_lookup[num_id] = description

# Map review business_ref to numeric ID
review_business_map = {}
for review in reviews_data:
    if 'business_ref' in review:
        ref_id = review['business_ref'].replace('businessref_', '')
        review_business_map[ref_id] = review_business_map.get(ref_id, 0) + 1

print(f'Found reviews for {len(review_business_map)} unique businesses')

# Sample business descriptions (for debugging)
print('Sample businesses:')
for i, (bus_id, desc) in enumerate(business_lookup.items()):
    if i < 3:
        print(f'  businessid_{bus_id}: {desc[:100]}...')
    else:
        break

result = {
    'status': 'data_loaded',
    'reviews_count': len(reviews_data),
    'businesses_count': len(business_lookup),
    'reviewed_businesses_count': len(review_business_map)
}

print('__RESULT__:')
print(json.dumps(result))"""

